mapper.select:

SELECT *
FROM 
	EXAM_POLICY
WHERE
	ENABLED_FLAG=1


AND TIME=#{time}


AND TOTAL_SCORE=#{totalScore}


AND PASS_SCORE=#{passScore}


AND EXAM_TIME_START=#{examTimeStart}


AND EXAM_TIME_END=#{examTimeEnd}


AND upper(SHOW_ANSWER) like upper('%${showAnswer}%')


AND upper(SHOW_SCORE) like upper('%${showScore}%')


AND upper(SAVE_PAGE) like upper('%${savePage}%')


AND upper(IS_UNIFY) like upper('%${isUnify}%')


AND upper(MEMO) like upper('%${memo}%')


AND LAST_UPDATE_DATE=#{lastUpdateDate}


AND LAST_UPDATED_BY=#{lastUpdatedBy}


AND CREATION_DATE=#{creationDate}


AND CREATED_BY=#{createdBy}


AND ENABLED_FLAG=#{enabledFlag}


AND PAPER_COUNT=#{paperCount}


AND GENERATE_CYCLE=#{generateCycle}


AND upper(TYPE) like upper('%${type}%')


AND ID=#{id}


AND upper(NAME) like upper('%${name}%')

ORDER BY ID


SELECT 
	*
FROM 
	EXAM_POLICY,EXAM_SCOPE_POLICY_REL
WHERE
	ENABLED_FLAG=1


AND TIME=#{bo.time}


AND TOTAL_SCORE=#{bo.totalScore}


AND PASS_SCORE=#{bo.passScore}


AND EXAM_TIME_START=#{bo.examTimeStart}


AND EXAM_TIME_END=#{bo.examTimeEnd}


AND upper(SHOW_ANSWER) like upper('%${bo.showAnswer}%')


AND upper(SHOW_SCORE) like upper('%${bo.showScore}%')


AND upper(SAVE_PAGE) like upper('%${bo.savePage}%')


AND upper(IS_UNIFY) like upper('%${bo.isUnify}%')


AND upper(MEMO) like upper('%${bo.memo}%')


AND LAST_UPDATE_DATE=#{bo.lastUpdateDate}


AND LAST_UPDATED_BY=#{bo.lastUpdatedBy}


AND CREATION_DATE=#{bo.creationDate}


AND CREATED_BY=#{bo.createdBy}


AND ENABLED_FLAG=#{bo.enabledFlag}


AND PAPER_COUNT=#{bo.paperCount}


AND GENERATE_CYCLE=#{bo.generateCycle}


AND upper(TYPE) like upper('%${bo.type}%')


AND ID=#{bo.id}


AND upper(NAME) like upper('%${bo.name}%')


AND ID=EXAM_SCOPE_POLICY_REL.POLICY_ID
AND EXAM_SCOPE_POLICY_REL.SCOPE_ID=#{bo.scopeId}

ORDER BY ${page.sortFieldName} DESC

SELECT ID, NAME, TIME, TOTAL_SCORE, PASS_SCORE, EXAM_TIME_START, EXAM_TIME_END, SHOW_ANSWER, SHOW_SCORE, SAVE_PAGE, IS_UNIFY, MEMO, LAST_UPDATE_DATE, LAST_UPDATED_BY, CREATION_DATE, CREATED_BY, ENABLED_FLAG, PAPER_COUNT, GENERATE_CYCLE, TYPE, SCOPE_ID FROM EXAM_POLICY, EXAM_SCOPE_POLICY_REL WHERE ENABLED_FLAG=1 AND EXAM_POLICY.ID=EXAM_SCOPE_POLICY_REL.POLICY_ID AND SCOPE_ID IN
#{id}
ORDER BY ID
